import{c as a,Q as o,j as s,m as n}from"./chunks/framework.CpfXsn6-.js";const u=JSON.parse('{"title":"URL方案（草案）","description":"","frontmatter":{"title":"URL方案（草案）"},"headers":[],"relativePath":"developer/url-spec.md","filePath":"developer/url-spec.md","lastUpdated":1779163937000}'),t={name:"developer/url-spec.md"};function p(c,e,d,l,r,i){return o(),s("div",null,[...e[0]||(e[0]=[n('<h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>encryption 格式修改为 ss;method:password</li></ul><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>感谢 @DuckSoft @StudentMain @phlinhng 对 Trojan-Go-Next URL 方案的讨论和贡献。<strong>目前 URL 方案为草案，需要更多的实践和讨论。</strong></p><p>Trojan-Go-Next<strong>客户端</strong>可以接受URL，以定位服务器资源。原则如下:</p><ul><li><p>遵守 URL 格式规范</p></li><li><p>保证人类可读，对机器友好</p></li><li><p>URL 的作用，是定位 Trojan-Go-Next 节点资源，方便资源分享</p></li></ul><p>需要注意，基于人类可读性的考虑，禁止将 base64 等编码数据嵌入 URL 中。首先， base64 编码不能保证传输安全，其意义在于在 ASCII 信道传输非 ASCII 数据。其次，如果需要保证分享 URL 时的传输安全，请对明文 URL 进行加密，而不是修改 URL 格式。</p><h2 id="格式" tabindex="-1">格式 <a class="header-anchor" href="#格式" aria-label="Permalink to &quot;格式&quot;">​</a></h2><p>基本格式如下，<code>$()</code> 代表此处需要 <code>encodeURIComponent</code>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trojan-go-next://</span></span>\n<span class="line"><span>    $(trojan-password)</span></span>\n<span class="line"><span>    @</span></span>\n<span class="line"><span>    trojan-host</span></span>\n<span class="line"><span>    :</span></span>\n<span class="line"><span>    port</span></span>\n<span class="line"><span>/?</span></span>\n<span class="line"><span>    sni=$(tls-sni.com)&amp;</span></span>\n<span class="line"><span>    type=$(original|ws|h2|h2+ws)&amp;</span></span>\n<span class="line"><span>        host=$(websocket-host.com)&amp;</span></span>\n<span class="line"><span>        path=$(/websocket/path)&amp;</span></span>\n<span class="line"><span>    encryption=$(ss;aes-256-gcm;ss-password)&amp;</span></span>\n<span class="line"><span>    plugin=$(...)</span></span>\n<span class="line"><span>#$(descriptive-text)</span></span></code></pre></div><p>例如</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trojan-go-next://password1234@google.com/?sni=microsoft.com&amp;type=ws&amp;host=youtube.com&amp;path=%2Fgo&amp;encryption=ss%3Baes-256-gcm%3Afuckgfw</span></span></code></pre></div><p>由于 Trojan-Go-Next 兼容 Trojan，所以对于 Trojan 的 URL 方案</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trojan://password@remote_host:remote_port</span></span></code></pre></div><p>可以兼容接受。它等价于</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trojan-go-next://password@remote_host:remote_port</span></span></code></pre></div><p>需要注意的是，一旦服务器使用了非Trojan兼容的功能，必须使用<code>trojan-go-next://</code>定位服务器。这样设计的目的是使得 Trojan-Go-Next 的 URL 不会被 Trojan 错误接受，避免污染 Trojan 用户的 URL 分享。同时，Trojan-Go-Next 确保可以兼容接受 Trojan 的 URL。</p><h2 id="详述" tabindex="-1">详述 <a class="header-anchor" href="#详述" aria-label="Permalink to &quot;详述&quot;">​</a></h2><p>注意：所有参数名和常数字符串均区分大小写。</p><h3 id="trojan-password" tabindex="-1"><code>trojan-password</code> <a class="header-anchor" href="#trojan-password" aria-label="Permalink to &quot;`trojan-password`&quot;">​</a></h3><p>Trojan 的密码。 不可省略，不能为空字符串，不建议含有非 ASCII 可打印字符。 必须使用 <code>encodeURIComponent</code> 编码。</p><h3 id="trojan-host" tabindex="-1"><code>trojan-host</code> <a class="header-anchor" href="#trojan-host" aria-label="Permalink to &quot;`trojan-host`&quot;">​</a></h3><p>节点 IP / 域名。 不可省略，不能为空字符串。 IPv6 地址必须扩方括号。 IDN 域名（如“百度.cn”）必须使用 <code>xn--xxxxxx</code> 格式。</p><h3 id="port" tabindex="-1"><code>port</code> <a class="header-anchor" href="#port" aria-label="Permalink to &quot;`port`&quot;">​</a></h3><p>节点端口。 省略时默认为 <code>443</code>。 必须取 <code>[1,65535]</code> 中的整数。</p><h3 id="tls或allowinsecure" tabindex="-1"><code>tls</code>或<code>allowInsecure</code> <a class="header-anchor" href="#tls或allowinsecure" aria-label="Permalink to &quot;`tls`或`allowInsecure`&quot;">​</a></h3><p>没有这个字段。 TLS 默认一直启用，除非有传输插件禁用它。 TLS 认证必须开启。无法使用根CA校验服务器身份的节点，不适合分享。</p><h3 id="sni" tabindex="-1"><code>sni</code> <a class="header-anchor" href="#sni" aria-label="Permalink to &quot;`sni`&quot;">​</a></h3><p>自定义 TLS 的 SNI。 省略时默认与 <code>trojan-host</code> 同值。不得为空字符串。</p><p>必须使用 <code>encodeURIComponent</code> 编码。</p><h3 id="type" tabindex="-1"><code>type</code> <a class="header-anchor" href="#type" aria-label="Permalink to &quot;`type`&quot;">​</a></h3><p>传输类型。 省略时默认为 <code>original</code>，但不可为空字符串。 目前可选值只有 <code>original</code> 和 <code>ws</code>，未来可能会有 <code>h2</code>、<code>h2+ws</code> 等取值。</p><p>当取值为 <code>original</code> 时，使用原始 Trojan 传输方式，无法方便通过 CDN。 当取值为 <code>ws</code> 时，使用 Websocket over TLS 传输。</p><h3 id="host" tabindex="-1"><code>host</code> <a class="header-anchor" href="#host" aria-label="Permalink to &quot;`host`&quot;">​</a></h3><p>自定义 HTTP <code>Host</code> 头。 可以省略，省略时值同 <code>trojan-host</code>。 可以为空字符串，但可能带来非预期情形。</p><p>警告：若你的端口非标准端口（不是 80 / 443），RFC 标准规定 <code>Host</code> 应在主机名后附上端口号，例如 <code>example.com:44333</code>。至于是否遵守，请自行斟酌。</p><p>必须使用 <code>encodeURIComponent</code> 编码。</p><h3 id="path" tabindex="-1"><code>path</code> <a class="header-anchor" href="#path" aria-label="Permalink to &quot;`path`&quot;">​</a></h3><p>当传输类型 <code>type</code> 取 <code>ws</code>、<code>h2</code>、<code>h2+ws</code> 时，此项有效。 不可省略，不可为空。 必须以 <code>/</code> 开头。 可以使用 URL 中的 <code>&amp;</code> <code>#</code> <code>?</code> 等字符，但应当是合法的 URL 路径。</p><p>必须使用 <code>encodeURIComponent</code> 编码。</p><h3 id="mux" tabindex="-1"><code>mux</code> <a class="header-anchor" href="#mux" aria-label="Permalink to &quot;`mux`&quot;">​</a></h3><p>没有这个字段。 当前服务器默认一直支持 <code>mux</code>。 启用 <code>mux</code> 与否各有利弊，应由客户端决定自己是否启用。URL的作用，是定位服务器资源，而不是规定用户使用偏好。</p><h3 id="encryption" tabindex="-1"><code>encryption</code> <a class="header-anchor" href="#encryption" aria-label="Permalink to &quot;`encryption`&quot;">​</a></h3><p>用于保证 Trojan 流量密码学安全的加密层。 可省略，默认为 <code>none</code>，即不使用加密。 不可以为空字符串。</p><p>必须使用 encodeURIComponent 编码。</p><p>使用 Shadowsocks 算法进行流量加密时，其格式为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ss;method:password</span></span></code></pre></div><p>其中 ss 是固定内容，method 是加密方法，必须为下列之一：</p><ul><li><code>aes-128-gcm</code></li><li><code>aes-256-gcm</code></li><li><code>chacha20-ietf-poly1305</code></li></ul><p>其中的 <code>password</code> 是 Shadowsocks 的密码，不得为空字符串。 <code>password</code> 中若包含分号，不需要进行转义。 <code>password</code> 应为英文可打印 ASCII 字符。</p><p>其他加密方案待定。</p><h3 id="plugin" tabindex="-1"><code>plugin</code> <a class="header-anchor" href="#plugin" aria-label="Permalink to &quot;`plugin`&quot;">​</a></h3><p>额外的插件选项。本字段保留。 可省略，但不可以为空字符串。</p><h3 id="url-fragment-后内容" tabindex="-1">URL Fragment (# 后内容) <a class="header-anchor" href="#url-fragment-后内容" aria-label="Permalink to &quot;URL Fragment (# 后内容)&quot;">​</a></h3><p>节点说明。 不建议省略，不建议为空字符串。</p><p>必须使用 <code>encodeURIComponent</code> 编码。</p>',56)])])}const m=a(t,[["render",p]]);export{u as __pageData,m as default};
